{{ 
  (() => {
    // 1. Verifica se é ADICIONAR (retorna vazio)
    if (appsmith.store.modalContexto?.entidade === 'TUTOR' && appsmith.store.modalContexto?.acaoTipo === "ADICIONAR") return "";

    // 2. Se for EDIÇÃO, pega o valor da tabela e limpa (apenas números)
    const telRaw = TableTutor.selectedRow.prop001_celular || "";
    const numeros = telRaw.toString().replace(/\D/g, "");

    // 3. Aplica a máscara baseada na quantidade de dígitos (10 ou 11)
    if (numeros.length === 11) {
      // Formato Celular: (00) 00000-0000
      return numeros.replace(/^(\d{2})(\d{5})(\d{4})$/, "($1) $2-$3");
    } else if (numeros.length === 10) {
      // Formato Fixo: (00) 0000-0000
      return numeros.replace(/^(\d{2})(\d{4})(\d{4})$/, "($1) $2-$3");
    }

    // Retorna o valor original se não tiver o tamanho padrão
    return numeros;
  })()
}}
